item.description:
 &lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;各种微生物&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note primary&#34;&gt;
&lt;p&gt;&lt;a href=&#34;/language/english/medical-roots/&#34;&gt;&lt;strong&gt;🚀颜色&lt;/strong&gt;&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/numbers&#34;&gt;💌数字&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/phobias/&#34;&gt;📌恐惧&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/microbiology/&#34;&gt;📌微生物&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;general&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#general&#34;&gt;#&lt;/a&gt; General&lt;/h2&gt;
&lt;p&gt;-bio-: life&lt;/p&gt;
&lt;p&gt;Bacterio-/-bacter: bacteria&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;bacteriophage 噬菌体&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Vir(o)-/-vir/-virus/-phage: virus, relating to virus&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;virologist&lt;/li&gt;
&lt;li&gt;antivirus&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Myc(o)-/Mycet(o)-/-myco-: fungus/fungi&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;mycologist 真菌学家&lt;/li&gt;
&lt;li&gt;dermatomycosis 皮肤真菌病&lt;/li&gt;
&lt;li&gt;onychomycosis 甲癣&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;locations&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#locations&#34;&gt;#&lt;/a&gt; Locations&lt;/h2&gt;
&lt;p&gt;Entero-: intestines&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;enterobacteriaceae 肠杆菌科&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Pneumo-: lung&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;pneumococcus 肺炎球菌&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Rhabdo-: straited muscle&lt;/p&gt;
&lt;p&gt;Adeno-: gland&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;adenovirus 腺病毒&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Gono-: reproductive&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;gonorrhoea 淋病&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Meningo-: meninges&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;meningococcus 脑膜炎双球菌&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Crypto-: hidden&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;cryptococcus 隐球菌&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;bacterial-shapes&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#bacterial-shapes&#34;&gt;#&lt;/a&gt; Bacterial Shapes&lt;/h2&gt;
&lt;p&gt;Staphylo-: cluster of grapes&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;staphylococcus 葡萄球菌&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Strepto-: chain&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;streptobacillus 链杆菌属&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Vibrio-: curved rod&lt;/p&gt;
&lt;p&gt;-bacillus/-bacilli: rod-shaped&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;streptobacilli 链杆菌&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;-coccus/-cocci: round/spherical&lt;/p&gt;
&lt;p&gt;Diplo-: double/two/paired&lt;/p&gt;
&lt;p&gt;Spirillum-: spiral&lt;/p&gt;
&lt;p&gt;Clostr-: spindle&lt;/p&gt;
&lt;p&gt;Echino-: spine-like;prickle-shaped&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;echinococcus 棘球绦虫&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Actino-:ray-like processes&lt;/p&gt;
&lt;h2 id=&#34;processes&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#processes&#34;&gt;#&lt;/a&gt; Processes&lt;/h2&gt;
&lt;p&gt;-pyogenes: pus-forming&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;bacterie pyogenes 化脓性细菌&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Lacto-: relating to lactic acid/lactose 乳酸 / 乳糖&lt;/p&gt;
&lt;p&gt;Aero-: air&lt;/p&gt;
&lt;p&gt;Sporo-: spore 芽胞，孢子&lt;/p&gt;
&lt;h2 id=&#34;viral-specifiers&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#viral-specifiers&#34;&gt;#&lt;/a&gt; Viral Specifiers&lt;/h2&gt;
&lt;p&gt;Picorna-: Pico RNA/small RNA&lt;/p&gt;
&lt;p&gt;Oncorna-: Onco RNA/cancer RNA&lt;/p&gt;
&lt;p&gt;Myxo-: mucus 粘液&lt;/p&gt;
&lt;p&gt;Parvo-: small&lt;/p&gt;
&lt;p&gt;Retro-: backward&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;retrovirus 逆转录病毒&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;aspergillus 曲霉菌&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;aspergillosis 曲霉病&lt;/li&gt;
&lt;/ul&gt;

 &lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;各种 Phobias&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note primary&#34;&gt;
&lt;p&gt;&lt;a href=&#34;/language/english/medical-roots/&#34;&gt;&lt;strong&gt;🚀颜色&lt;/strong&gt;&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/numbers&#34;&gt;💌数字&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/phobias/&#34;&gt;📌恐惧&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/microbiology/&#34;&gt;📌微生物&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;animals&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#animals&#34;&gt;#&lt;/a&gt; Animals&lt;/h2&gt;
&lt;p&gt;Zoo-: animals&lt;/p&gt;
&lt;p&gt;Ailuro-/Gato-: cats&lt;/p&gt;
&lt;p&gt;Api-: bees ^b69035&lt;/p&gt;
&lt;p&gt;Anatidae-: ducks&lt;/p&gt;
&lt;p&gt;Alektoro-: chickens&lt;/p&gt;
&lt;p&gt;Cyno-: dogs&lt;/p&gt;
&lt;p&gt;Entomo-: insects&lt;/p&gt;
&lt;p&gt;Equino-: horses&lt;/p&gt;
&lt;p&gt;Galeo-: sharks&lt;/p&gt;
&lt;p&gt;Ichthyo-: fish&lt;/p&gt;
&lt;p&gt;Katsarida-: cockroaches&lt;/p&gt;
&lt;p&gt;Kinemorto-: zombies ^f0960c&lt;/p&gt;
&lt;p&gt;Lepidopetro-: butterflies&lt;/p&gt;
&lt;p&gt;Motte-: moths&lt;/p&gt;
&lt;p&gt;Myrmeco-: ants&lt;/p&gt;
&lt;p&gt;Muso-: mice&lt;/p&gt;
&lt;p&gt;Ornitho-: birds&lt;/p&gt;
&lt;p&gt;Ophidio-: snake&lt;/p&gt;
&lt;p&gt;Sphekso-: wasps&lt;/p&gt;
&lt;h2 id=&#34;environment&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#environment&#34;&gt;#&lt;/a&gt; Environment&lt;/h2&gt;
&lt;p&gt;Acro-: heights&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;acrophobia 恐高&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Agora-: open/crowded spaces&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;agoraphobia 公共场所恐怖症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Aqua-/Hydro-: water&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;aquaphobia&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Aero-: flying&lt;/p&gt;
&lt;p&gt;Basi-: falling&lt;/p&gt;
&lt;p&gt;Astra-: thunder and lightening&lt;/p&gt;
&lt;p&gt;Batho-: depths&lt;/p&gt;
&lt;p&gt;Claustro-: small spaces&lt;/p&gt;
&lt;p&gt;Chrono-: future&lt;/p&gt;
&lt;p&gt;Didaskaleino-: school&lt;/p&gt;
&lt;p&gt;Ergo-: work&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;ergophobia 害怕上班&lt;/li&gt;
&lt;li&gt;ergonomic 人类工程学&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Ligyro-: loud noises&lt;/p&gt;
&lt;p&gt;Nycto-: darkness&lt;/p&gt;
&lt;p&gt;Nosocome-: hospitals ^78821f&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;nosocomial infections 院内感染&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Ombro-: rain&lt;/p&gt;
&lt;h2 id=&#34;spirits&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#spirits&#34;&gt;#&lt;/a&gt; Spirits&lt;/h2&gt;
&lt;p&gt;Coulro-: clown&lt;/p&gt;
&lt;p&gt;Andro-: men&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;androphobia&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Gyno-: women&lt;/p&gt;
&lt;p&gt;Iatro-: doctors [[#^78821f]]&lt;/p&gt;
&lt;p&gt;Achondro-: person of short stature&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;achondrophobia （恐矮症？）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Auto-: abandonment&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;autophobia&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Achieveme-: success&lt;/p&gt;
&lt;p&gt;Atychi-: failure&lt;/p&gt;
&lt;p&gt;Aphenphosm-: intimacy&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;aphenphosmphobia 接触恐惧&lt;/li&gt;
&lt;li&gt;also known as&lt;/li&gt;
&lt;li&gt;haphephobia&lt;/li&gt;
&lt;li&gt;aphephobia&lt;/li&gt;
&lt;li&gt;haptophobia&lt;/li&gt;
&lt;li&gt;thixophobix&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Athazagora-: being forgotten&lt;/p&gt;
&lt;p&gt;Aglio-: pain&lt;/p&gt;
&lt;p&gt;Allodoxa-: opinions&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;allodoxaphobia 选择恐惧症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Cacomor-: overweight people&lt;/p&gt;
&lt;p&gt;Disposo-: getting rid of things&lt;/p&gt;
&lt;p&gt;Enochlo-: crowds&lt;/p&gt;
&lt;p&gt;Emeto-: vomiting&lt;/p&gt;
&lt;p&gt;Gamo-: commitment&lt;/p&gt;
&lt;p&gt;Gerasco-: getting old&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;gerascophobia 害怕变老&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Glosso-: public speaking/tongue&lt;/p&gt;
&lt;p&gt;Metathesio-: change&lt;/p&gt;
&lt;p&gt;Mono-: being alone&lt;/p&gt;
&lt;p&gt;Toko-: pregnancy;giving birth;having children&lt;/p&gt;
&lt;p&gt;Telephono-: talking on the phone&lt;/p&gt;
&lt;p&gt;Veho-: driving&lt;/p&gt;
&lt;h2 id=&#34;objects&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#objects&#34;&gt;#&lt;/a&gt; Objects&lt;/h2&gt;
&lt;p&gt;Cibo-: food&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;cibophobia 厌食症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Banana-: bananas&lt;/p&gt;
&lt;p&gt;Chaeto-: hair&lt;/p&gt;
&lt;p&gt;Catoptro-: mirrors&lt;/p&gt;
&lt;p&gt;Coaster-: roller coasters&lt;/p&gt;
&lt;p&gt;Gephyro-: bridges&lt;/p&gt;
&lt;p&gt;Globo-: balloons&lt;/p&gt;
&lt;p&gt;Myso-: germs/contamination&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;mysophobia 洁癖&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Numero-: numbers;calculations&lt;/p&gt;
&lt;p&gt;Omphalo-: navel;belly button 脐&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;omphalocele 脐突出&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Pano-: everything&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;panophobia&lt;/li&gt;
&lt;li&gt;pancytopenia 各类血细胞减少症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Podo-: feet&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;podiatry 足病治疗&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Phobo-: fear&lt;/p&gt;
&lt;p&gt;Philo-: love&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;philia&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Paraskevidekatria-: Friday the 13th&lt;/p&gt;
&lt;p&gt;Pedio-: dolls&lt;/p&gt;
&lt;p&gt;Phasmo-: ghosts&lt;/p&gt;
&lt;p&gt;Pyro-: fire&lt;/p&gt;
&lt;p&gt;Pogono-: beards&lt;/p&gt;
&lt;p&gt;Pseudodysphagia-: fear of choking&lt;/p&gt;
&lt;p&gt;Photo-: light&lt;/p&gt;
&lt;p&gt;Ranida-: frogs&lt;/p&gt;
&lt;p&gt;Sidonglobo-: cotton balls; plastic foams&lt;/p&gt;
&lt;p&gt;Scelero-: crime&lt;/p&gt;
&lt;p&gt;Somni-: sleep&lt;/p&gt;
&lt;p&gt;Samhaino-: Halloween&lt;/p&gt;
&lt;p&gt;Scoleci-: worms&lt;/p&gt;
&lt;p&gt;Theo-: god&lt;/p&gt;
&lt;p&gt;Triskaideka-: Number 13&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;deka: Number 10&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Trypo-: holes&lt;/p&gt;
&lt;p&gt;Thanato-: death&lt;/p&gt;
&lt;p&gt;Trypano-: needles&lt;/p&gt;
&lt;p&gt;Techno-: technology&lt;/p&gt;
&lt;p&gt;Thalasso-: ocean&lt;/p&gt;
&lt;p&gt;Tapho-: buried alive&lt;/p&gt;
&lt;p&gt;Xeno-:unknown;different;foreign&lt;/p&gt;

 &lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;各种数字&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note primary&#34;&gt;
&lt;p&gt;&lt;a href=&#34;/language/english/medical-roots/&#34;&gt;&lt;strong&gt;🚀颜色&lt;/strong&gt;&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/numbers&#34;&gt;💌数字&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/phobias/&#34;&gt;📌恐惧&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/microbiology/&#34;&gt;📌微生物&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;numbers&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#numbers&#34;&gt;#&lt;/a&gt; Numbers&lt;/h2&gt;
&lt;p&gt;Mono-:1&lt;/p&gt;
&lt;p&gt;Di-:2&lt;/p&gt;
&lt;p&gt;Tri-:3&lt;/p&gt;
&lt;p&gt;Quad-/Tetra-:4&lt;/p&gt;
&lt;p&gt;Pent(a)-:5&lt;/p&gt;
&lt;p&gt;Hex(a)-:6&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;hexagon&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Hept(a)-:7&lt;/p&gt;
&lt;p&gt;Oct(a)-:8&lt;/p&gt;
&lt;p&gt;Non(a):9&lt;/p&gt;
&lt;p&gt;Dec(i):10&lt;/p&gt;
&lt;p&gt;Haplo-/Uni:single&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;unilateral&lt;/li&gt;
&lt;li&gt;haplotype 单倍体&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Primi-: first&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;primigravida 初孕妇&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Dipl(o)-/Dupli-:double&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;diplococci 双球菌&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Hemi-/Semi-: half&lt;/p&gt;
&lt;h2 id=&#34;quantity&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#quantity&#34;&gt;#&lt;/a&gt; Quantity&lt;/h2&gt;
&lt;p&gt;Iso-/Equi-: equal; equality&lt;/p&gt;
&lt;p&gt;Eu-/Normo-: Average;Normal&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;euthermic 适温的&lt;/li&gt;
&lt;li&gt;normotension 血压正常&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Hyper-: 高的；超出正常水平的；上升的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;hyperthermic 体温过高的&lt;/li&gt;
&lt;li&gt;hypercapnea 高碳酸血症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Hypo-：低的；低于正常水平的；下降的&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;hypoxic 缺氧的&lt;/li&gt;
&lt;li&gt;hypoxia 缺氧&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Poly-：很多&lt;/p&gt;
&lt;p&gt;Oligo-/Pauci-：很少；一些&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;oliguria 少尿症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Pan-/Omni-: All&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;omnipotent 无所不能的&lt;/li&gt;
&lt;li&gt;panorama 全景&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;A-/An-: absent;lacking&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;anemia 贫血&lt;/li&gt;
&lt;li&gt;adrenal 肾上的&lt;/li&gt;
&lt;li&gt;atrophy 萎缩&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Nulli-: none;lacking&lt;/p&gt;

 &lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;不是阿&lt;br /&gt;
 2023 年的我看到这个八卦&lt;br /&gt;
怎么都想不起来是什么&lt;br /&gt;
你怎么没有记下来啊&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;今天 Clubhouse 的一个 Room 里听了一下午十分有料的八卦➕后面有人提到了 drugs 的体验以及 burning man 之类的一些奇奇怪怪新奇的东西&lt;/p&gt;
&lt;h2 id=&#34;电子产品&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#电子产品&#34;&gt;#&lt;/a&gt; 电子产品&lt;/h2&gt;
&lt;p&gt;朝鲜仅对外国人开放 3g/4g 用的阿里郎牌📱&lt;br /&gt;
网费挺贵的 当地人商店和外国人商店（以美元 / 人民币结算）&lt;/p&gt;
&lt;h2 id=&#34;金日成学习堂&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#金日成学习堂&#34;&gt;#&lt;/a&gt; 金日成学习堂&lt;/h2&gt;
&lt;p&gt;阅兵的时候站的地方，不能摆和某三胖一样的动作&lt;/p&gt;
&lt;h2 id=&#34;杂&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#杂&#34;&gt;#&lt;/a&gt; 杂&lt;/h2&gt;
&lt;p&gt;可以去朝鲜见亲戚（不能带 English/Korean）&lt;/p&gt;
&lt;p&gt;两个导游带一个 18 个人的团 （高端阶层生活和我们差不多 不能换朝鲜币 （导游 A 给的几千块朝鲜币是导游 B 一个月的工资&lt;/p&gt;
&lt;p&gt;60 年前在朝鲜打仗，60 年后回来看，人倒在谈判桌，死在谈判桌上（共同警备区太长&lt;/p&gt;
&lt;p&gt;封国之前，金日成广场看晚会，大家都是站在广场上 10w 人左右，外宾团走到最前面，2-3 小时的歌舞表演，牡丹峰压轴，最后倒数过年放烟花，全国直播的跨年晚会&lt;/p&gt;
&lt;p&gt;住的都是羊角岛酒店&lt;br /&gt;
羊角岛酒店地下有赌场&lt;/p&gt;
&lt;p&gt;阿里郎（十万人团体舞，对面小学生不停的换图片，机械整齐，08 的时候平壤热水使用受限，冬天可能 2-3 个月才能洗澡，当时拍照不能随便拍路上的行人，在火车上被抓了，一车厢的人被查照片，花了五千块行贿了查照片的人，很怕在北朝鲜被枪毙了）&lt;/p&gt;
&lt;p&gt;朝鲜有名创优品，17 左右开的，后来名创优品去美国上市，所以就把朝鲜的控股交出去了&lt;/p&gt;
&lt;p&gt;鸭绿江上拍照，给十几块钱就能接受了&lt;/p&gt;
&lt;h2 id=&#34;政治&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#政治&#34;&gt;#&lt;/a&gt; 政治&lt;/h2&gt;
&lt;p&gt;泰永浩，脱北者，保守党，首尔当了议员&lt;br /&gt;
疫情期间，泰永好说金正恩病危，后面自己名誉受损&lt;/p&gt;
&lt;h2 id=&#34;朝鲜冷面&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#朝鲜冷面&#34;&gt;#&lt;/a&gt; 朝鲜冷面&lt;/h2&gt;
&lt;p&gt;平壤冷面（清汤 —- 最正宗的&lt;br /&gt;
深度游玩的方向&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;平壤科学技术大学（招汉语 / 英语老师 和美国合办的&lt;/li&gt;
&lt;li&gt;金日成综合大学（朝鲜语语言课，纠正南朝鲜的口音&lt;/li&gt;
&lt;li&gt;大同江大桥不坚固，导游会跟踪你，可以甩掉，一个照相机才 30 多块钱 rmb&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;两个导游&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#两个导游&#34;&gt;#&lt;/a&gt; 两个导游&lt;/h2&gt;
&lt;p&gt;沪普老金，72 道行政区划（算了韩国的），后来说只有 36 道&lt;/p&gt;
&lt;h2 id=&#34;小金&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小金&#34;&gt;#&lt;/a&gt; 小金&lt;/h2&gt;
&lt;p&gt;聊了价值观，家庭观，婚龄，小金会看韩剧，看到三角恋之类的情节，不知道好不好，朝鲜平均女生婚龄 30 岁左右，对中文资源接触较多，每晚脱队，晚上观察到的景象：平壤的街道灯火通明，两旁住宅楼也是灯火通明，不拉窗帘，可以看到家具，领导人画像和大立柜&lt;/p&gt;
&lt;p&gt;日间脱队行动：去大街上转悠，拍了普通人肖像，被人举报，导游训斥了一番，最后一天早上九点左右，当时 12 年不能带手机，军事管制区和有守卫的地方不能照相，最后迟到了差点回不去了，幸好同学拖住了&lt;/p&gt;
&lt;h2 id=&#34;xing-西北一个大叔1995年去的朝鲜&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#xing-西北一个大叔1995年去的朝鲜&#34;&gt;#&lt;/a&gt; XING 西北一个大叔，1995 年去的朝鲜&lt;/h2&gt;
&lt;p&gt;十岁左右中朝少年沟通夏令营去交流，金日成刚去世，所以延迟了两周（国丧），丹东呆了两周，去了黑市，买了朝鲜货币，1rmb 买 100 朝鲜币&lt;/p&gt;
&lt;p&gt;当时学了一首金日成将军之歌，当时平壤比北京繁华的多，地铁干净，高楼很高，每次上完菜（精美，量少），服务员就消失。去酒店二楼买麦芽糖来果腹。一起玩的小学生他们都很快乐，最深印象的是招待在国际儿童村（外面一个金日成雕像，游乐场完全没有人，免费绿豆汤喝，去娱乐室玩红白机）那个酒店现在还没建完，差一个尖的金字塔。&lt;/p&gt;
&lt;p&gt;因为金日成刚去世，所以每天只能看两小时电视，有个人会走出来，讲金日成的故事，然后痛哭流涕，然后雪花。&lt;/p&gt;
&lt;h2 id=&#34;一个女生爷爷出生在北朝鲜半岛&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一个女生爷爷出生在北朝鲜半岛&#34;&gt;#&lt;/a&gt; 一个女生，爷爷出生在北朝鲜半岛&lt;/h2&gt;
&lt;p&gt;90 年代的一个故事&lt;br /&gt;
后面留学到中国&lt;br /&gt;
每年会送物资给北朝鲜的亲戚&lt;br /&gt;
送物资的方式&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;写信，比如说时间地点在哪里等&lt;/li&gt;
&lt;li&gt;亲戚来自己家，拿很多东西，再回北朝鲜&lt;br /&gt;
遇到脱北者&lt;/li&gt;
&lt;li&gt;父母都不在了&lt;/li&gt;
&lt;li&gt;晚上游过鸭绿江&lt;/li&gt;
&lt;li&gt;在树林里躲了三天被人发现&lt;/li&gt;
&lt;li&gt;有她家的联系方式&lt;/li&gt;
&lt;li&gt;20 多岁的成年女孩，照顾了一个月左右，怕被抓走，送到青岛，饭店打工，几年后据说在餐厅干了不到半年，去 ktv 做了小姐，说是来钱比较快&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;lee-谈脱北者&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#lee-谈脱北者&#34;&gt;#&lt;/a&gt; Lee 谈脱北者&lt;/h2&gt;
&lt;p&gt;本来逃到中国是应该送回去的，但是送回去后就枪毙了，后面就是送韩国大使馆，自行处理&lt;/p&gt;
&lt;p&gt;建国后，河南新乡，专门朝鲜脱北者聚集地，从河南去港澳，再去了韩国&lt;/p&gt;
&lt;h2 id=&#34;fred&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#fred&#34;&gt;#&lt;/a&gt; Fred&lt;/h2&gt;
&lt;p&gt;自建团➕导游，18 年去朝鲜元山市，能看到很多贫瘠山村，路也不太能走。能看到征兵，能看到海边有上下学的孩子。&lt;br /&gt;
大楼&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;一年内建完（变成三年建完）&lt;/li&gt;
&lt;li&gt;涂料定期有人搞&lt;/li&gt;
&lt;li&gt;所有建筑都没怎么装空调&lt;/li&gt;
&lt;li&gt;住在高丽饭店，特级宾馆，顶上有旋转餐厅，有一半的房间是被挡住的（可能是什么军事用处），朝鲜导游有手机的（和 iPhone 很像，只能用 2G）&lt;/li&gt;
&lt;li&gt;夜晚，当地游乐场从早上玩到晚上&lt;/li&gt;
&lt;li&gt;朝鲜的地方特色，分房制&lt;/li&gt;
&lt;li&gt;有梦想，就写下心愿，就能选上读书（然而说不出来）&lt;/li&gt;
&lt;li&gt;对领导人的称呼，历代都不同，永远的 xxx&lt;/li&gt;
&lt;li&gt;孩子玩的，以上海为背景，打日本人的游戏&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;一个男生&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#一个男生&#34;&gt;#&lt;/a&gt; 一个男生&lt;/h2&gt;
&lt;p&gt;鸭绿江&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;🇨🇳这边的公路很好，村也发展不错，朝鲜那边都是小房子，无法判断有没有住&lt;/li&gt;
&lt;li&gt;沿途有军事设施&lt;/li&gt;
&lt;li&gt;中间有条火车线，有运输东西&lt;/li&gt;
&lt;li&gt;还有小型火车站，之前每个站上面都有金日成头像&lt;/li&gt;
&lt;li&gt;鸭绿江很窄&lt;/li&gt;
&lt;li&gt;一般情况下治安挺好，但有时候晚上会有人过来偷东西，偷日常用品，我们这是村里登记，然后有补偿&lt;/li&gt;
&lt;li&gt;临江（共同城市，县），他们那是村&lt;/li&gt;
&lt;li&gt;往那边扔饮料，有捡走的，晚上就黑了，只有路灯，偶尔有手电巡逻的&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;zhongda&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#zhongda&#34;&gt;#&lt;/a&gt; zhongda&lt;/h2&gt;
&lt;p&gt;跟了一个画廊团（家具城，面向富人&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;丹东到平壤的火车上，遇上一个美国韩裔平壤科技大学行政级工作人员（后来回国后，有人因为间谍行为被抓了，不知道有没有这个人&lt;/li&gt;
&lt;li&gt;八月份类似于建军节，放假，就去海边游玩，&lt;/li&gt;
&lt;li&gt;拍照与政治气候有关，可能宽松的时候，就随便拍，但漏洞是 sd 卡，或者是删掉的照片，可以恢复备份&lt;/li&gt;
&lt;li&gt;签证是在纸上，留下出入境的痕迹，后来去美国，不能隐瞒这个事情&lt;/li&gt;
&lt;li&gt;北京出发去平壤，就看不出来&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;现在去平壤，有市民已经开始养宠物了&lt;/p&gt;

 &lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;本文全都是 &lt;code&gt;颜色&lt;/code&gt; 内容&lt;br /&gt;
但是没有 &lt;code&gt;颜色内容&lt;/code&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;因为博主实在不知道放什么东西&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note primary&#34;&gt;
&lt;p&gt;&lt;a href=&#34;/language/english/medical-roots/&#34;&gt;&lt;strong&gt;🚀颜色&lt;/strong&gt;&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/numbers&#34;&gt;💌数字&lt;/a&gt; - &lt;a href=&#34;/language/english/medical-roots/phobias/&#34;&gt;📌恐惧&lt;/a&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;color&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#color&#34;&gt;#&lt;/a&gt; Color&lt;/h2&gt;
&lt;p&gt;Chromo-/Chromato-: color&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;hemachromatosis 血色素沉着&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Photo-: light&lt;/p&gt;
&lt;p&gt;-opaque: non-transparent&lt;br /&gt;
-lucent: transparent&lt;/p&gt;
&lt;h2 id=&#34;red&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#red&#34;&gt;#&lt;/a&gt; Red&lt;/h2&gt;
&lt;p&gt;Erythro-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;erythroderma 红皮病&lt;/li&gt;
&lt;li&gt;erythrocyte 红细胞，红血球&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Eosino-&lt;/p&gt;
&lt;p&gt;Rubr(i/o)-&lt;/p&gt;
&lt;p&gt;Rhod-&lt;/p&gt;
&lt;h2 id=&#34;blue&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#blue&#34;&gt;#&lt;/a&gt; Blue&lt;/h2&gt;
&lt;p&gt;Cyano-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;cyanide 氰化物&lt;/li&gt;
&lt;li&gt;cyanosis 发绀，青紫&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;green&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#green&#34;&gt;#&lt;/a&gt; Green&lt;/h2&gt;
&lt;p&gt;Chloro：绿色&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;chlorophyll 叶绿素&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;yellow&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#yellow&#34;&gt;#&lt;/a&gt; Yellow&lt;/h2&gt;
&lt;p&gt;Flav(o)-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;flavonoid 类黄酮&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Jaund(o)-: french word jaune&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;jaundice 黄疸&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Lunte(o)-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;luteus 黄体&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Xanth(o)-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;xanthoma 黄瘤；黄色瘤；黄疣（一种皮肤病）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Cirrhos-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;cirrhosis 肝硬化&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;orange&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#orange&#34;&gt;#&lt;/a&gt; Orange&lt;/h2&gt;
&lt;p&gt;Cirrhos-&lt;/p&gt;
&lt;p&gt;Carotene-/-caroten-: 胡萝卜素&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;hypercarotenemia 高胡萝卜素血症&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;pinkrosey&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#pinkrosey&#34;&gt;#&lt;/a&gt; Pink/Rosey&lt;/h2&gt;
&lt;p&gt;Roseo-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;roseola 红疹，蔷薇疹&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;brown&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#brown&#34;&gt;#&lt;/a&gt; Brown&lt;/h2&gt;
&lt;p&gt;Fusc(o)-&lt;/p&gt;
&lt;h2 id=&#34;gold&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#gold&#34;&gt;#&lt;/a&gt; Gold&lt;/h2&gt;
&lt;p&gt;Chrys(o)-&lt;/p&gt;
&lt;h2 id=&#34;purple&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#purple&#34;&gt;#&lt;/a&gt; Purple&lt;/h2&gt;
&lt;p&gt;Purpur(o)-&lt;/p&gt;
&lt;p&gt;Porphyr(o)-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Porphyria 卟啉症 (一种遗传性卟啉代谢的病态紊乱)&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;white&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#white&#34;&gt;#&lt;/a&gt; White&lt;/h2&gt;
&lt;p&gt;Leuko-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;leukocyte 白细胞&lt;/li&gt;
&lt;li&gt;leukemia 白血病&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Albin(o)-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;albinism 白化病&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Albus-&lt;/p&gt;
&lt;p&gt;Cand-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;candida 念珠菌&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;black&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#black&#34;&gt;#&lt;/a&gt; Black&lt;/h2&gt;
&lt;p&gt;Melano-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;melanoma 黑色素瘤&lt;/li&gt;
&lt;li&gt;melanocyte 黑素细胞&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Nigr-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;substantia nigra 黑质，塞梅林氏神经节&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;grey&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#grey&#34;&gt;#&lt;/a&gt; Grey&lt;/h2&gt;
&lt;p&gt;Polio-: gray matter of brain/spinal cord&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;poliomyelitis 脊髓灰质炎，小儿麻痹症&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Glauco-&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;glaucoma 青光眼&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Tephro-&lt;/p&gt;
&lt;h2 id=&#34;silver&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#silver&#34;&gt;#&lt;/a&gt; Silver&lt;/h2&gt;
&lt;p&gt;Argent-&lt;/p&gt;
